def task_1(list_1: List[int]) -> int:
    n = len(list_1)
    f = [[0] * n for _ in range(n)]
    d = {x: i for (i, x) in enumerate(list_1)}
    for i in range(n):
        for j in range(i):
            f[i][j] = 2
    ans = 0
    for i in range(2, n):
        for j in range(1, i):
            t = list_1[i] - list_1[j]
            if t in d and (k := d[t]) < j:
                f[i][j] = max(f[i][j], f[j][k] + 1)
                ans = max(ans, f[i][j])
    task_1_out = ans
    return task_1_out
```

