    n = len(list_1)
    stk = []
    left = [-1] * n
    for (i, x) in enumerate(list_1):
        while stk and list_1[stk[-1]] > x:
            stk.pop()
        if stk:
            left[i] = stk[-1]
        stk.append(i)
    stk = []
    right = [n] * n
    for i in range(n - 1, -1, -1):
        x = list_1[i]
        while stk and list_1[stk[-1]] >= x:
            stk.pop()
        if stk:
            right[i] = stk[-1]
        stk.append(i)
    f = [0] * n
    for (i, x) in enumerate(list_1):
        if i and x >= list_1[i - 1]:
            f[i] = f[i - 1] + x
        else:
            j = left[i]
            f[i] = x * (i - j) + (f[j] if j != -1 else 0)
    g = [0] * n
    for i in range(n - 1, -1, -1):
        if i < n - 1 and list_1[i] >= list_1[i + 1]:
            g[i] = g[i + 1] + list_1[i]
        else:
            j = right[i]
            g[i] = list_1[i] * (j - i) + (g[j] if j != n else 0)
    task_1_out = max((a + b - c for (a, b, c) in zip(f, g, list_1)))
    return task_1_out
