def task_1(val_1: int) -> int:
    while 1:
        (t, s, i) = (val_1, 0, 2)
        while i <= val_1 // i:
            while val_1 % i == 0:
                val_1 //= i
                s += i
            i += 1
        if val_1 > 1:
            s += val_1
        if s == t:
            task_1_out = t
            return task_1_out
        val_1 = s
```

